using System.Text.RegularExpressions;
using DocSummary.Models;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarization service that ranks sentences by word-frequency
/// scoring and returns the top-ranked sentences in their original order.
/// </summary>
public partial class DocumentSummarizationService : IDocumentSummarizationService
{
    // Common English stop words excluded from frequency scoring.
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","i","you","he","she","it",
        "we","they","me","him","her","us","them","my","your","his","its","our",
        "their","this","that","these","those","in","on","at","to","for","of",
        "with","by","from","as","into","about","between","through","during",
        "before","after","above","below","not","no","nor","so","if","then",
        "than","too","very","just","also","each","every","all","any","few",
        "more","most","other","some","such","only","own","same","both","what",
        "which","who","whom","how","when","where","why","while","up","out",
    };

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"\b[a-zA-Z]+\b")]
    private static partial Regex WordTokenizer();

    public SummarizeResponse Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitSentences(documentText);

        if (sentences.Length == 0)
        {
            return new SummarizeResponse
            {
                Summary = string.Empty,
                OriginalCharacterCount = documentText.Length,
            };
        }

        if (sentences.Length <= maxSentences)
        {
            return new SummarizeResponse
            {
                Summary = documentText.Trim(),
                OriginalCharacterCount = documentText.Length,
                SummaryCharacterCount = documentText.Trim().Length,
                OriginalSentenceCount = sentences.Length,
                SummarySentenceCount = sentences.Length,
            };
        }

        var wordFrequencies = BuildWordFrequencies(sentences);
        var sentenceScores = ScoreSentences(sentences, wordFrequencies);

        // Pick the top-scored sentences, then re-order by original position.
        var topIndices = sentenceScores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .OrderBy(i => i)
            .ToList();

        var summary = string.Join(" ", topIndices.Select(i => sentences[i]));

        return new SummarizeResponse
        {
            Summary = summary,
            OriginalCharacterCount = documentText.Length,
            SummaryCharacterCount = summary.Length,
            OriginalSentenceCount = sentences.Length,
            SummarySentenceCount = topIndices.Count,
        };
    }

    private static string[] SplitSentences(string text)
    {
        return SentenceSplitter()
            .Split(text.Trim())
            .Where(s => !string.IsNullOrWhiteSpace(s))
            .Select(s => s.Trim())
            .ToArray();
    }

    private static Dictionary<string, int> BuildWordFrequencies(string[] sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var match in WordTokenizer().EnumerateMatches(sentence))
            {
                var word = sentence.AsSpan(match.Index, match.Length).ToString();
                if (StopWords.Contains(word) || word.Length < 2)
                    continue;

                if (!frequencies.TryAdd(word, 1))
                    frequencies[word]++;
            }
        }

        return frequencies;
    }

    private static double[] ScoreSentences(string[] sentences, Dictionary<string, int> wordFrequencies)
    {
        var maxFrequency = wordFrequencies.Count > 0 ? wordFrequencies.Values.Max() : 1;
        var scores = new double[sentences.Length];

        for (var i = 0; i < sentences.Length; i++)
        {
            double score = 0;
            int wordCount = 0;

            foreach (var match in WordTokenizer().EnumerateMatches(sentences[i]))
            {
                var word = sentences[i].AsSpan(match.Index, match.Length).ToString();
                wordCount++;

                if (wordFrequencies.TryGetValue(word, out var freq))
                    score += (double)freq / maxFrequency;
            }

            // Normalize by word count to avoid bias toward longer sentences.
            scores[i] = wordCount > 0 ? score / wordCount : 0;
        }

        return scores;
    }
}

